css_template:
#{{ID}} .rep-logo-box {
    z-index: 50;
    position: absolute;
    top: 0;
    left: 0;
    width: {{#if LOGO_WIDTH}}{{LOGO_WIDTH}}px{{else}}150px{{/if}};
    height: {{#if LOGO_HEIGHT}}{{LOGO_HEIGHT}}px{{else}}80px{{/if}};
    background: {{#if TRANSPARENT}}transparent{{else}}{{PRIMARY_BG}}{{/if}};
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 10px;
    box-sizing: border-box;
    box-shadow: {{#if TRANSPARENT}}none{{else}}{{BOX_SHADOW}}{{/if}};
    opacity: 0;
    transform-origin: left center;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
    border-right: {{#if TRANSPARENT}}none{{else}}2px solid rgba(255,255,255,0.1){{/if}};
}
#{{ID}} .rep-logo-img {
    max-width: 90%;
    max-height: 90%;
    object-fit: contain;
    filter: {{#if TRANSPARENT}}none{{else}}drop-shadow(0 2px 4px rgba(0,0,0,0.5)){{/if}};
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-logo-box");
    root.__slt_show = () => {
        return GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
    };
    root.__slt_hide = () => {
        return GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
    };
})();
